import { LitElement, html, css, customElement, state } from '@umbraco-cms/backoffice/external/lit';
import { tagManagerRepository, type TagGroup, type CmsTag } from '../api/index.js';

@customElement('tagmanager-dashboard')
export class TagManagerDashboardElement extends LitElement {
	@state()
	private _tagGroups: TagGroup[] = [];

	@state()
	private _selectedGroup: string | null = null;

	@state()
	private _tagsInGroup: CmsTag[] = [];

	@state()
	private _loading = true;

	connectedCallback() {
		super.connectedCallback();
		this._loadTagGroups();
	}

	private async _loadTagGroups() {
		this._loading = true;
		this._tagGroups = await tagManagerRepository.getTagGroups();
		console.log('Tag groups loaded:', this._tagGroups);
		this._loading = false;
	}

	private async _selectGroup(groupName: string) {
		this._selectedGroup = groupName;
		this._loading = true;
		this._tagsInGroup = await tagManagerRepository.getTagsInGroup(groupName);
		this._loading = false;
	}

	private _openTagWorkspace(tagId: number) {
		// Navigate to tag workspace
		history.pushState(null, '', `section/tagmanager/workspace/tagmanager-tag/edit/${tagId}`);
	}

	render() {
		return html`
			<uui-box headline="Tag Manager">
				<div id="tag-manager-container">
					${this._loading
						? html`<uui-loader></uui-loader>`
						: html`
								<div class="tag-groups">
									<h3>Tag Groups</h3>
									<uui-menu-item
										label="All Groups"
										@click=${() => (this._selectedGroup = null)}>
									</uui-menu-item>
									${this._tagGroups.map(
										(group) => html`
											<uui-menu-item
												label="${group.group}"
												@click=${() => this._selectGroup(group.group)}
												?active=${this._selectedGroup === group.group}>
											</uui-menu-item>
										`
									)}
								</div>

								${this._selectedGroup
									? html`
											<div class="tags-list">
												<h3>Tags in ${this._selectedGroup}</h3>
												<uui-table>
													<uui-table-head>
														<uui-table-head-cell>Tag</uui-table-head-cell>
														<uui-table-head-cell>Usage Count</uui-table-head-cell>
														<uui-table-head-cell>Actions</uui-table-head-cell>
													</uui-table-head>
													${this._tagsInGroup.map(
														(tag) => html`
															<uui-table-row>
																<uui-table-cell>${tag.tag}</uui-table-cell>
																<uui-table-cell>${tag.noTaggedNodes}</uui-table-cell>
																<uui-table-cell>
																	<uui-button
																		label="Edit"
																		look="primary"
																		@click=${() => this._openTagWorkspace(tag.id)}>
																		Edit
																	</uui-button>
																</uui-table-cell>
															</uui-table-row>
														`
													)}
												</uui-table>
											</div>
									  `
									: html`<p>Select a tag group to view tags</p>`}
						  `}
				</div>
			</uui-box>
		`;
	}

	static styles = css`
		:host {
			display: block;
			padding: var(--uui-size-layout-1);
		}

		#tag-manager-container {
			display: grid;
			grid-template-columns: 250px 1fr;
			gap: var(--uui-size-layout-1);
		}

		.tag-groups {
			border-right: 1px solid var(--uui-color-border);
			padding-right: var(--uui-size-space-4);
		}

		.tags-list {
			padding-left: var(--uui-size-space-4);
		}

		h3 {
			margin-top: 0;
		}
	`;
}

declare global {
	interface HTMLElementTagNameMap {
		'tagmanager-dashboard': TagManagerDashboardElement;
	}
}

